'use client';

import type { ReactNode } from 'react';
import { useEffect, useMemo, useState } from 'react';
import { useRouter } from 'next/navigation';

type TabKey = 'overview' | 'people' | 'instructors' | 'categories' | 'content' | 'cms' | 'messages' | 'settings';
type Box<T> = { data: T; error: string };

const basePath = process.env.NEXT_PUBLIC_BASE_PATH || '/backend';
const adminLoginPath = '/admin/login';

const shell = { padding: 24, fontFamily: 'Arial, sans-serif', background: 'linear-gradient(180deg, #eef2ff 0%, #f8fafc 28%, #ffffff 100%)', minHeight: '100vh' } as const;
const card = { background: '#fff', borderRadius: 18, padding: 20, boxShadow: '0 16px 40px rgba(15,23,42,0.08)' } as const;
const tabs: TabKey[] = ['overview', 'people', 'instructors', 'categories', 'content', 'cms', 'messages', 'settings'];
const box = <T,>(data: T): Box<T> => ({ data, error: '' });
const slugify = (value: string) => value.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
const fmtDate = (value?: string) => !value ? 'Not set' : new Date(value).toLocaleString();
const money = (value?: number) => value === undefined ? 'Free' : new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 }).format(value);
const parseLines = (value: string) => value.split(',').map((part) => part.trim()).filter(Boolean);
const parseLinks = (value: string) => value.split('\n').map((line) => line.trim()).filter(Boolean).map((line) => { const [label, href] = line.split('|'); return { label: (label || '').trim(), href: (href || '').trim() }; });
const parseNavItems = (value: string) => value.split('\n').map((line) => line.trim()).filter(Boolean).map((line, index) => { const [title, href = '', type = 'link', active = 'true'] = line.split('|'); return { sort: index + 1, title: title.trim(), value: href.trim(), type: type.trim(), slug: slugify(title), items: [], active: active.trim().toLowerCase() !== 'false' }; });
const navItemsToText = (items?: any[]) => (items || []).map((item) => `${item.title || ''}|${item.value || ''}|${item.type || 'link'}|${item.active === false ? 'false' : 'true'}`).join('\n');

async function api<T>(path: string, token: string, method = 'GET', body?: unknown): Promise<T> {
  const resolvedPath = path.startsWith('/') ? `${basePath}${path}` : path;
  const response = await fetch(resolvedPath, { method, headers: { Authorization: `Bearer ${token}`, Accept: 'application/json', 'Content-Type': 'application/json' }, body: body ? JSON.stringify(body) : undefined });
  const json = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error((json && (json.message || json.error)) || `Request failed: ${response.status}`);
  return (json.data ?? json) as T;
}

export default function BackendAdminPage() {
  const router = useRouter();
  const [token, setToken] = useState('');
  const [ready, setReady] = useState(false);
  const [tab, setTab] = useState<TabKey>('overview');
  const [query, setQuery] = useState('');
  const [message, setMessage] = useState('');
  const [overview, setOverview] = useState<Box<any>>(box({ metrics: {} }));
  const [users, setUsers] = useState<Box<any[]>>(box([]));
  const [instructors, setInstructors] = useState<Box<any[]>>(box([]));
  const [courses, setCourses] = useState<Box<any[]>>(box([]));
  const [courseCategories, setCourseCategories] = useState<Box<any[]>>(box([]));
  const [courseChildren, setCourseChildren] = useState<Box<any[]>>(box([]));
  const [exams, setExams] = useState<Box<any[]>>(box([]));
  const [examCategories, setExamCategories] = useState<Box<any[]>>(box([]));
  const [blogs, setBlogs] = useState<Box<any[]>>(box([]));
  const [blogCategories, setBlogCategories] = useState<Box<any[]>>(box([]));
  const [pages, setPages] = useState<Box<any[]>>(box([]));
  const [pageSections, setPageSections] = useState<Box<any[]>>(box([]));
  const [navbars, setNavbars] = useState<Box<any[]>>(box([]));
  const [footers, setFooters] = useState<Box<any[]>>(box([]));
  const [contactMessages, setContactMessages] = useState<Box<any[]>>(box([]));
  const [newsletters, setNewsletters] = useState<Box<any[]>>(box([]));
  const [settings, setSettings] = useState<Box<any>>(box({}));

  const [userForm, setUserForm] = useState<any>({ name: '', email: '', role: 'student', isActive: true, mobile: '', headline: '', skills: '', password: '', status: '1' });
  const [instructorForm, setInstructorForm] = useState<any>({ userId: '', designation: '', status: 'pending', biography: '', skills: '' });
  const [courseCategoryForm, setCourseCategoryForm] = useState<any>({ title: '', slug: '', icon: '', sort: '0', status: true, description: '' });
  const [courseChildForm, setCourseChildForm] = useState<any>({ title: '', slug: '', icon: '', sort: '0', status: true, description: '', courseCategoryId: '' });
  const [examCategoryForm, setExamCategoryForm] = useState<any>({ title: '', slug: '', icon: '', sort: '0', status: true, description: '' });
  const [blogCategoryForm, setBlogCategoryForm] = useState<any>({ name: '', slug: '', icon: '', sort: '0', status: 'active', description: '' });
  const [blogForm, setBlogForm] = useState<any>({ title: '', slug: '', status: 'draft', description: '', keywords: '', blogCategoryId: '' });
  const [pageForm, setPageForm] = useState<any>({ name: '', title: '', slug: '', type: 'inner_page', active: true, description: '' });
  const [sectionForm, setSectionForm] = useState<any>({ name: '', slug: '', title: '', sort: '0', active: true, pageId: '', description: '', backgroundColor: '' });
  const [navbarForm, setNavbarForm] = useState<any>({ title: '', slug: '', active: false, itemsText: '' });
  const [footerForm, setFooterForm] = useState<any>({ title: '', slug: '', active: false, itemsText: '' });
  const [newsletterForm, setNewsletterForm] = useState<any>({ subject: '', description: '' });
  const [settingsForm, setSettingsForm] = useState<any>({ siteName: '', siteDescription: '', socialLinks: '' });

  useEffect(() => {
    const saved = localStorage.getItem('backend_auth_token') || '';
    if (!saved) { router.replace(adminLoginPath); return; }
    setToken(saved); setReady(true);
  }, [router]);

  async function refreshAll(authToken = token) {
    if (!authToken) return;
    try {
      const [o, u, i, c, cc, cch, e, ec, bc, b, p, ps, n, f, cm, nl, s] = await Promise.all([
        api<any>('/api/dashboard/admin/overview', authToken),
        api<any[]>('/api/admin/users', authToken),
        api<any[]>('/api/admin/instructors', authToken),
        api<any[]>('/api/admin/courses', authToken),
        api<any[]>('/api/admin/course-categories', authToken),
        api<any[]>('/api/admin/course-category-children', authToken),
        api<any[]>('/api/admin/exams', authToken),
        api<any[]>('/api/admin/exam-categories', authToken),
        api<any[]>('/api/admin/blog-categories', authToken),
        api<any[]>('/api/admin/blogs', authToken),
        api<any[]>('/api/admin/pages', authToken),
        api<any[]>('/api/admin/page-sections', authToken),
        api<any[]>('/api/admin/navbars', authToken),
        api<any[]>('/api/admin/footers', authToken),
        api<any[]>('/api/admin/contact-messages', authToken),
        api<any[]>('/api/admin/newsletters', authToken),
        api<any>('/api/admin/settings', authToken),
      ]);
      setOverview(box(o)); setUsers(box(u)); setInstructors(box(i)); setCourses(box(c)); setCourseCategories(box(cc)); setCourseChildren(box(cch)); setExams(box(e)); setExamCategories(box(ec)); setBlogCategories(box(bc)); setBlogs(box(b)); setPages(box(p)); setPageSections(box(ps)); setNavbars(box(n)); setFooters(box(f)); setContactMessages(box(cm)); setNewsletters(box(nl)); setSettings(box(s));
      setSettingsForm({ siteName: s.siteName || '', siteDescription: s.siteDescription || '', socialLinks: (s.socialLinks || []).map((item: any) => `${item.label || ''}|${item.href || ''}`).join('\n') });
    } catch (error) {
      const msg = error instanceof Error ? error.message : 'Failed to load backend data';
      setMessage(msg);
      if (msg.toLowerCase().includes('unauthorized') || msg.toLowerCase().includes('forbidden')) { localStorage.removeItem('backend_auth_token'); router.replace(adminLoginPath); }
    }
  }

  useEffect(() => { if (ready && token) refreshAll(token); }, [ready, token]);
  const q = query.trim().toLowerCase();
  const find = (parts: any[]) => !q || parts.some((part) => String(part || '').toLowerCase().includes(q));
  const filteredUsers = users.data.filter((item) => find([item.name, item.email, item.role, item.mobile, item.headline]));
  const filteredInstructors = instructors.data.filter((item) => find([item.designation, item.status, item.biography]));
  const filteredCourseCategories = courseCategories.data.filter((item) => find([item.title, item.slug, item.description]));
  const filteredCourseChildren = courseChildren.data.filter((item) => find([item.title, item.slug, item.description]));
  const filteredExamCategories = examCategories.data.filter((item) => find([item.title, item.slug, item.description]));
  const filteredBlogCategories = blogCategories.data.filter((item) => find([item.name, item.slug, item.description]));
  const filteredBlogs = blogs.data.filter((item) => find([item.title, item.slug, item.status, item.keywords]));
  const filteredPages = pages.data.filter((item) => find([item.name, item.title, item.slug, item.type]));
  const filteredSections = pageSections.data.filter((item) => find([item.name, item.slug, item.title, item.description]));
  const filteredNavbars = navbars.data.filter((item) => find([item.title, item.slug]));
  const filteredFooters = footers.data.filter((item) => find([item.title, item.slug]));
  const filteredNewsletters = newsletters.data.filter((item) => find([item.subject, item.description]));
  const filteredMessages = contactMessages.data.filter((item) => find([item.name, item.email, item.subject, item.message]));

  const metricCards = useMemo(() => Object.entries({ Users: overview.data.metrics?.users || users.data.length, Instructors: overview.data.metrics?.instructors || instructors.data.length, Courses: overview.data.metrics?.courses || courses.data.length, CourseCategories: overview.data.metrics?.courseCategories || courseCategories.data.length, Exams: overview.data.metrics?.exams || exams.data.length, ExamCategories: overview.data.metrics?.examCategories || examCategories.data.length, Blogs: overview.data.metrics?.blogs || blogs.data.length, BlogCategories: overview.data.metrics?.blogCategories || blogCategories.data.length, Pages: overview.data.metrics?.pages || pages.data.length, Sections: overview.data.metrics?.pageSections || pageSections.data.length, Navbars: overview.data.metrics?.navbars || navbars.data.length, Footers: overview.data.metrics?.footers || footers.data.length, Newsletters: overview.data.metrics?.newsletters || newsletters.data.length, Messages: overview.data.metrics?.contactMessages || contactMessages.data.length }), [overview.data, users.data.length, instructors.data.length, courses.data.length, courseCategories.data.length, exams.data.length, examCategories.data.length, blogs.data.length, blogCategories.data.length, pages.data.length, pageSections.data.length, navbars.data.length, footers.data.length, newsletters.data.length, contactMessages.data.length]);

  function clearUser() { setUserForm({ name: '', email: '', role: 'student', isActive: true, mobile: '', headline: '', skills: '', password: '', status: '1' }); }
  function clearInstructor() { setInstructorForm({ userId: '', designation: '', status: 'pending', biography: '', skills: '' }); }
  function clearCategoryForms() { setCourseCategoryForm({ title: '', slug: '', icon: '', sort: '0', status: true, description: '' }); setCourseChildForm({ title: '', slug: '', icon: '', sort: '0', status: true, description: '', courseCategoryId: '' }); setExamCategoryForm({ title: '', slug: '', icon: '', sort: '0', status: true, description: '' }); setBlogCategoryForm({ name: '', slug: '', icon: '', sort: '0', status: 'active', description: '' }); }
  function clearContentForms() { setBlogForm({ title: '', slug: '', status: 'draft', description: '', keywords: '', blogCategoryId: '' }); setPageForm({ name: '', title: '', slug: '', type: 'inner_page', active: true, description: '' }); setSectionForm({ name: '', slug: '', title: '', sort: '0', active: true, pageId: '', description: '', backgroundColor: '' }); }
  async function saveUser() { const body = { name: userForm.name, email: userForm.email, role: userForm.role, isActive: userForm.isActive, status: Number(userForm.status || 1), mobile: userForm.mobile, headline: userForm.headline, skills: parseLines(userForm.skills), password: userForm.password }; await api(userForm.id ? `/api/admin/users/${userForm.id}` : '/api/admin/users', token, userForm.id ? 'PATCH' : 'POST', body); setMessage(userForm.id ? 'User updated' : 'User created'); clearUser(); await refreshAll(); }
  async function deleteUser() { if (!userForm.id) return; await api(`/api/admin/users/${userForm.id}`, token, 'DELETE'); setMessage('User deleted'); clearUser(); await refreshAll(); }
  async function saveInstructor() { const body = { userId: instructorForm.userId || undefined, designation: instructorForm.designation, status: instructorForm.status, biography: instructorForm.biography, skills: parseLines(instructorForm.skills) }; await api(instructorForm.id ? `/api/admin/instructors/${instructorForm.id}` : '/api/admin/instructors', token, instructorForm.id ? 'PATCH' : 'POST', body); setMessage(instructorForm.id ? 'Instructor updated' : 'Instructor created'); clearInstructor(); await refreshAll(); }
  async function deleteInstructor() { if (!instructorForm.id) return; await api(`/api/admin/instructors/${instructorForm.id}`, token, 'DELETE'); setMessage('Instructor deleted'); clearInstructor(); await refreshAll(); }
  async function saveCourseCategory() { const body = { title: courseCategoryForm.title, slug: courseCategoryForm.slug || slugify(courseCategoryForm.title), icon: courseCategoryForm.icon, sort: Number(courseCategoryForm.sort || 0), status: courseCategoryForm.status, description: courseCategoryForm.description }; await api(courseCategoryForm.id ? `/api/admin/course-categories/${courseCategoryForm.id}` : '/api/admin/course-categories', token, courseCategoryForm.id ? 'PATCH' : 'POST', body); setMessage(courseCategoryForm.id ? 'Course category updated' : 'Course category created'); clearCategoryForms(); await refreshAll(); }
  async function deleteCourseCategory() { if (!courseCategoryForm.id) return; await api(`/api/admin/course-categories/${courseCategoryForm.id}`, token, 'DELETE'); setMessage('Course category deleted'); clearCategoryForms(); await refreshAll(); }
  async function saveCourseChild() { const body = { title: courseChildForm.title, slug: courseChildForm.slug || slugify(courseChildForm.title), icon: courseChildForm.icon, sort: Number(courseChildForm.sort || 0), status: courseChildForm.status, description: courseChildForm.description, courseCategoryId: courseChildForm.courseCategoryId || undefined }; await api(courseChildForm.id ? `/api/admin/course-category-children/${courseChildForm.id}` : '/api/admin/course-category-children', token, courseChildForm.id ? 'PATCH' : 'POST', body); setMessage(courseChildForm.id ? 'Course child category updated' : 'Course child category created'); clearCategoryForms(); await refreshAll(); }
  async function deleteCourseChild() { if (!courseChildForm.id) return; await api(`/api/admin/course-category-children/${courseChildForm.id}`, token, 'DELETE'); setMessage('Course child category deleted'); clearCategoryForms(); await refreshAll(); }
  async function saveExamCategory() { const body = { title: examCategoryForm.title, slug: examCategoryForm.slug || slugify(examCategoryForm.title), icon: examCategoryForm.icon, sort: Number(examCategoryForm.sort || 0), status: examCategoryForm.status, description: examCategoryForm.description }; await api(examCategoryForm.id ? `/api/admin/exam-categories/${examCategoryForm.id}` : '/api/admin/exam-categories', token, examCategoryForm.id ? 'PATCH' : 'POST', body); setMessage(examCategoryForm.id ? 'Exam category updated' : 'Exam category created'); clearCategoryForms(); await refreshAll(); }
  async function deleteExamCategory() { if (!examCategoryForm.id) return; await api(`/api/admin/exam-categories/${examCategoryForm.id}`, token, 'DELETE'); setMessage('Exam category deleted'); clearCategoryForms(); await refreshAll(); }
  async function saveBlogCategory() { const body = { name: blogCategoryForm.name, slug: blogCategoryForm.slug || slugify(blogCategoryForm.name), icon: blogCategoryForm.icon, sort: Number(blogCategoryForm.sort || 0), status: blogCategoryForm.status, description: blogCategoryForm.description }; await api(blogCategoryForm.id ? `/api/admin/blog-categories/${blogCategoryForm.id}` : '/api/admin/blog-categories', token, blogCategoryForm.id ? 'PATCH' : 'POST', body); setMessage(blogCategoryForm.id ? 'Blog category updated' : 'Blog category created'); clearCategoryForms(); await refreshAll(); }
  async function deleteBlogCategory() { if (!blogCategoryForm.id) return; await api(`/api/admin/blog-categories/${blogCategoryForm.id}`, token, 'DELETE'); setMessage('Blog category deleted'); clearCategoryForms(); await refreshAll(); }
  async function saveBlog() { const body = { title: blogForm.title, slug: blogForm.slug || slugify(blogForm.title), status: blogForm.status, description: blogForm.description, keywords: blogForm.keywords, blogCategoryId: blogForm.blogCategoryId || undefined }; await api(blogForm.id ? `/api/admin/blogs/${blogForm.id}` : '/api/admin/blogs', token, blogForm.id ? 'PATCH' : 'POST', body); setMessage(blogForm.id ? 'Blog updated' : 'Blog created'); clearContentForms(); await refreshAll(); }
  async function deleteBlog() { if (!blogForm.id) return; await api(`/api/admin/blogs/${blogForm.id}`, token, 'DELETE'); setMessage('Blog deleted'); clearContentForms(); await refreshAll(); }
  async function savePage() { const body = { name: pageForm.name || pageForm.title, title: pageForm.title, slug: pageForm.slug || slugify(pageForm.title), type: pageForm.type, active: pageForm.active, description: pageForm.description }; await api(pageForm.id ? `/api/admin/pages/${pageForm.id}` : '/api/admin/pages', token, pageForm.id ? 'PATCH' : 'POST', body); setMessage(pageForm.id ? 'Page updated' : 'Page created'); clearContentForms(); await refreshAll(); }
  async function deletePage() { if (!pageForm.id) return; await api(`/api/admin/pages/${pageForm.id}`, token, 'DELETE'); setMessage('Page deleted'); clearContentForms(); await refreshAll(); }
  async function saveSection() { const body = { name: sectionForm.name, slug: sectionForm.slug || slugify(sectionForm.name), title: sectionForm.title, sort: Number(sectionForm.sort || 0), active: sectionForm.active, pageId: sectionForm.pageId || undefined, description: sectionForm.description, backgroundColor: sectionForm.backgroundColor }; await api(sectionForm.id ? `/api/admin/page-sections/${sectionForm.id}` : '/api/admin/page-sections', token, sectionForm.id ? 'PATCH' : 'POST', body); setMessage(sectionForm.id ? 'Page section updated' : 'Page section created'); clearContentForms(); await refreshAll(); }
  async function deleteSection() { if (!sectionForm.id) return; await api(`/api/admin/page-sections/${sectionForm.id}`, token, 'DELETE'); setMessage('Page section deleted'); clearContentForms(); await refreshAll(); }
  async function saveNavbar() { const body = { title: navbarForm.title, slug: navbarForm.slug || slugify(navbarForm.title), active: navbarForm.active, items: parseNavItems(navbarForm.itemsText) }; await api(navbarForm.id ? `/api/admin/navbars/${navbarForm.id}` : '/api/admin/navbars', token, navbarForm.id ? 'PATCH' : 'POST', body); setMessage(navbarForm.id ? 'Navbar updated' : 'Navbar created'); setNavbarForm({ title: '', slug: '', active: false, itemsText: '' }); await refreshAll(); }
  async function deleteNavbar() { if (!navbarForm.id) return; await api(`/api/admin/navbars/${navbarForm.id}`, token, 'DELETE'); setMessage('Navbar deleted'); setNavbarForm({ title: '', slug: '', active: false, itemsText: '' }); await refreshAll(); }
  async function saveFooter() { const body = { title: footerForm.title, slug: footerForm.slug || slugify(footerForm.title), active: footerForm.active, items: parseNavItems(footerForm.itemsText) }; await api(footerForm.id ? `/api/admin/footers/${footerForm.id}` : '/api/admin/footers', token, footerForm.id ? 'PATCH' : 'POST', body); setMessage(footerForm.id ? 'Footer updated' : 'Footer created'); setFooterForm({ title: '', slug: '', active: false, itemsText: '' }); await refreshAll(); }
  async function deleteFooter() { if (!footerForm.id) return; await api(`/api/admin/footers/${footerForm.id}`, token, 'DELETE'); setMessage('Footer deleted'); setFooterForm({ title: '', slug: '', active: false, itemsText: '' }); await refreshAll(); }
  async function saveNewsletter() { const body = { subject: newsletterForm.subject, description: newsletterForm.description }; await api(newsletterForm.id ? `/api/admin/newsletters/${newsletterForm.id}` : '/api/admin/newsletters', token, newsletterForm.id ? 'PATCH' : 'POST', body); setMessage(newsletterForm.id ? 'Newsletter updated' : 'Newsletter created'); setNewsletterForm({ subject: '', description: '' }); await refreshAll(); }
  async function deleteNewsletter() { if (!newsletterForm.id) return; await api(`/api/admin/newsletters/${newsletterForm.id}`, token, 'DELETE'); setMessage('Newsletter deleted'); setNewsletterForm({ subject: '', description: '' }); await refreshAll(); }
  async function deleteMessage(id?: string) { if (!id) return; await api(`/api/admin/contact-messages/${id}`, token, 'DELETE'); setMessage('Contact message deleted'); await refreshAll(); }
  async function saveSettings() { await api('/api/admin/settings', token, 'PATCH', { siteName: settingsForm.siteName, siteDescription: settingsForm.siteDescription, socialLinks: parseLinks(settingsForm.socialLinks) }); setMessage('Settings updated'); await refreshAll(); }

  return (
    <main style={shell}>
      <div style={{ maxWidth: 1520, margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', gap: 16, alignItems: 'flex-start', flexWrap: 'wrap', marginBottom: 24 }}>
          <div>
            <div style={{ display: 'inline-flex', padding: '6px 12px', borderRadius: 999, background: '#dbeafe', color: '#1d4ed8', fontSize: 12, fontWeight: 800, textTransform: 'uppercase' }}>Backend Control Panel</div>
            <h1 style={{ margin: '12px 0 8px', fontSize: 38, color: '#0f172a' }}>EDVO Backend Admin</h1>
            <p style={{ margin: 0, color: '#475569', maxWidth: 860 }}>All major Laravel-mirrored modules are now visible inside admin: users, instructors, categories, blogs, CMS, messages, and settings.</p>
          </div>
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
            <button type="button" onClick={() => refreshAll()} style={{ padding: '12px 18px', borderRadius: 12, border: 0, background: '#0f172a', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>Refresh</button>
            <button type="button" onClick={() => { localStorage.removeItem('backend_auth_token'); router.replace(adminLoginPath); }} style={{ padding: '12px 18px', borderRadius: 12, border: '1px solid #fecaca', background: '#fff1f2', color: '#b91c1c', fontWeight: 700, cursor: 'pointer' }}>Logout</button>
          </div>
        </div>

        <div style={{ ...card, marginBottom: 20, display: 'flex', justifyContent: 'space-between', gap: 16, alignItems: 'center', flexWrap: 'wrap' }}>
          <div><div style={{ fontWeight: 800 }}>Search</div><div style={{ color: '#64748b', fontSize: 14 }}>Filter the visible records in the current tab.</div></div>
          <input value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Search current tab..." style={{ minWidth: 340, flex: '1 1 340px', padding: 14, borderRadius: 12, border: '1px solid #cbd5e1' }} />
        </div>

        {message ? <div style={{ ...card, marginBottom: 20, background: '#ecfeff', color: '#155e75' }}>{message}</div> : null}
        <div style={{ marginBottom: 20, display: 'flex', gap: 12, flexWrap: 'wrap' }}>{tabs.map((item) => <button key={item} type="button" onClick={() => setTab(item)} style={{ padding: '12px 16px', borderRadius: 12, border: tab === item ? '1px solid #0f172a' : '1px solid #cbd5e1', background: tab === item ? '#0f172a' : '#fff', color: tab === item ? '#fff' : '#0f172a', textTransform: 'capitalize', fontWeight: 700, cursor: 'pointer' }}>{item}</button>)}</div>

        {tab === 'overview' ? <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 16 }}>{metricCards.map(([label, value]) => <div key={label} style={card}><div style={{ fontSize: 12, textTransform: 'uppercase', color: '#64748b' }}>{label}</div><div style={{ fontSize: 32, fontWeight: 800, marginTop: 8 }}>{String(value)}</div></div>)}</div> : null}

        {tab === 'people' ? <div style={{ display: 'grid', gridTemplateColumns: '1.1fr 0.9fr', gap: 20 }}><div style={card}><h2 style={{ marginTop: 0 }}>Users</h2><SimpleTable columns={['Name','Email','Role','Active','Status','Headline']} rows={filteredUsers.map((item) => [item.name, item.email, item.role, item.isActive === false ? 'No' : 'Yes', item.status ?? 1, item.headline || ''])} emptyLabel="No users found" onSelect={(index) => setUserForm({ id: filteredUsers[index].id, name: filteredUsers[index].name, email: filteredUsers[index].email, role: filteredUsers[index].role, isActive: filteredUsers[index].isActive !== false, mobile: filteredUsers[index].mobile || '', headline: filteredUsers[index].headline || '', skills: (filteredUsers[index].skills || []).join(', '), password: '', status: String(filteredUsers[index].status ?? 1) })} /></div><div style={card}><h2 style={{ marginTop: 0 }}>{userForm.id ? 'Edit User' : 'Add User'}</h2><FormGrid>{textField('Name', userForm.name, (v) => setUserForm({ ...userForm, name: v }))}{textField('Email', userForm.email, (v) => setUserForm({ ...userForm, email: v }), 'email')}{selectField('Role', userForm.role, (v) => setUserForm({ ...userForm, role: v }), ['student','instructor','admin'])}{checkboxField('Active', userForm.isActive, (v) => setUserForm({ ...userForm, isActive: v }))}{textField('Status Number', userForm.status, (v) => setUserForm({ ...userForm, status: v }), 'number')}{textField('Mobile', userForm.mobile, (v) => setUserForm({ ...userForm, mobile: v }))}{textField('Headline', userForm.headline, (v) => setUserForm({ ...userForm, headline: v }))}{textAreaField('Skills', userForm.skills, (v) => setUserForm({ ...userForm, skills: v }), 'Comma separated skills')}{textField(userForm.id ? 'New Password' : 'Password', userForm.password, (v) => setUserForm({ ...userForm, password: v }), 'password')}</FormGrid>{actionRow(() => saveUser(), () => clearUser(), userForm.id ? () => deleteUser() : undefined, userForm.id ? 'Update User' : 'Add User')}</div></div> : null}

        {tab === 'instructors' ? <div style={{ display: 'grid', gridTemplateColumns: '1.1fr 0.9fr', gap: 20 }}><div style={card}><h2 style={{ marginTop: 0 }}>Instructors</h2><SimpleTable columns={['Designation','Status','Skills','Linked User']} rows={filteredInstructors.map((item) => [item.designation || '', item.status || 'pending', (item.skills || []).length, item.userId || ''])} emptyLabel="No instructors found" onSelect={(index) => setInstructorForm({ id: filteredInstructors[index]._id || filteredInstructors[index].id, userId: String(filteredInstructors[index].userId || ''), designation: filteredInstructors[index].designation || '', status: filteredInstructors[index].status || 'pending', biography: filteredInstructors[index].biography || '', skills: (filteredInstructors[index].skills || []).join(', ') })} /></div><div style={card}><h2 style={{ marginTop: 0 }}>{instructorForm.id ? 'Edit Instructor' : 'Add Instructor'}</h2><FormGrid>{selectField('Linked User', instructorForm.userId, (v) => setInstructorForm({ ...instructorForm, userId: v }), [''].concat(users.data.map((item) => item.id || item._id || '')))}{textField('Designation', instructorForm.designation, (v) => setInstructorForm({ ...instructorForm, designation: v }))}{selectField('Status', instructorForm.status, (v) => setInstructorForm({ ...instructorForm, status: v }), ['pending','approved','rejected'])}{textAreaField('Biography', instructorForm.biography, (v) => setInstructorForm({ ...instructorForm, biography: v }))}{textAreaField('Skills', instructorForm.skills, (v) => setInstructorForm({ ...instructorForm, skills: v }), 'Comma separated skills')}</FormGrid>{actionRow(() => saveInstructor(), () => clearInstructor(), instructorForm.id ? () => deleteInstructor() : undefined, instructorForm.id ? 'Update Instructor' : 'Add Instructor')}</div></div> : null}
        {tab === 'categories' ? <div style={{ display: 'grid', gap: 20 }}><DualCard title="Course Categories" columns={['Title','Slug','Status','Sort']} rows={filteredCourseCategories.map((item) => [item.title, item.slug, item.status === false ? 'Inactive' : 'Active', item.sort || 0])} onSelect={(index) => setCourseCategoryForm({ id: filteredCourseCategories[index]._id || filteredCourseCategories[index].id, title: filteredCourseCategories[index].title, slug: filteredCourseCategories[index].slug, icon: filteredCourseCategories[index].icon || '', sort: String(filteredCourseCategories[index].sort || 0), status: filteredCourseCategories[index].status !== false, description: filteredCourseCategories[index].description || '' })} emptyLabel="No course categories" form={<><FormGrid>{textField('Title', courseCategoryForm.title, (v) => setCourseCategoryForm({ ...courseCategoryForm, title: v, slug: courseCategoryForm.id ? courseCategoryForm.slug : slugify(v) }))}{textField('Slug', courseCategoryForm.slug, (v) => setCourseCategoryForm({ ...courseCategoryForm, slug: slugify(v) }))}{textField('Icon', courseCategoryForm.icon, (v) => setCourseCategoryForm({ ...courseCategoryForm, icon: v }))}{textField('Sort', courseCategoryForm.sort, (v) => setCourseCategoryForm({ ...courseCategoryForm, sort: v }), 'number')}{checkboxField('Active', courseCategoryForm.status, (v) => setCourseCategoryForm({ ...courseCategoryForm, status: v }))}{textAreaField('Description', courseCategoryForm.description, (v) => setCourseCategoryForm({ ...courseCategoryForm, description: v }))}</FormGrid>{actionRow(() => saveCourseCategory(), () => clearCategoryForms(), courseCategoryForm.id ? () => deleteCourseCategory() : undefined, courseCategoryForm.id ? 'Update Course Category' : 'Add Course Category')}</>} formTitle={courseCategoryForm.id ? 'Edit Course Category' : 'Add Course Category'} /><DualCard title="Course Child Categories" columns={['Title','Slug','Status','Parent']} rows={filteredCourseChildren.map((item) => [item.title, item.slug, item.status === false ? 'Inactive' : 'Active', item.courseCategoryId || ''])} onSelect={(index) => setCourseChildForm({ id: filteredCourseChildren[index]._id || filteredCourseChildren[index].id, title: filteredCourseChildren[index].title, slug: filteredCourseChildren[index].slug, icon: filteredCourseChildren[index].icon || '', sort: String(filteredCourseChildren[index].sort || 0), status: filteredCourseChildren[index].status !== false, description: filteredCourseChildren[index].description || '', courseCategoryId: filteredCourseChildren[index].courseCategoryId || '' })} emptyLabel="No course child categories" form={<><FormGrid>{textField('Title', courseChildForm.title, (v) => setCourseChildForm({ ...courseChildForm, title: v, slug: courseChildForm.id ? courseChildForm.slug : slugify(v) }))}{textField('Slug', courseChildForm.slug, (v) => setCourseChildForm({ ...courseChildForm, slug: slugify(v) }))}{selectField('Parent Category', courseChildForm.courseCategoryId, (v) => setCourseChildForm({ ...courseChildForm, courseCategoryId: v }), [''].concat(courseCategories.data.map((item) => item._id || item.id || '')))}{textField('Icon', courseChildForm.icon, (v) => setCourseChildForm({ ...courseChildForm, icon: v }))}{textField('Sort', courseChildForm.sort, (v) => setCourseChildForm({ ...courseChildForm, sort: v }), 'number')}{checkboxField('Active', courseChildForm.status, (v) => setCourseChildForm({ ...courseChildForm, status: v }))}{textAreaField('Description', courseChildForm.description, (v) => setCourseChildForm({ ...courseChildForm, description: v }))}</FormGrid>{actionRow(() => saveCourseChild(), () => clearCategoryForms(), courseChildForm.id ? () => deleteCourseChild() : undefined, courseChildForm.id ? 'Update Child Category' : 'Add Child Category')}</>} formTitle={courseChildForm.id ? 'Edit Child Category' : 'Add Child Category'} /><DualCard title="Exam Categories" columns={['Title','Slug','Status','Sort']} rows={filteredExamCategories.map((item) => [item.title, item.slug, item.status === false ? 'Inactive' : 'Active', item.sort || 0])} onSelect={(index) => setExamCategoryForm({ id: filteredExamCategories[index]._id || filteredExamCategories[index].id, title: filteredExamCategories[index].title, slug: filteredExamCategories[index].slug, icon: filteredExamCategories[index].icon || '', sort: String(filteredExamCategories[index].sort || 0), status: filteredExamCategories[index].status !== false, description: filteredExamCategories[index].description || '' })} emptyLabel="No exam categories" form={<><FormGrid>{textField('Title', examCategoryForm.title, (v) => setExamCategoryForm({ ...examCategoryForm, title: v, slug: examCategoryForm.id ? examCategoryForm.slug : slugify(v) }))}{textField('Slug', examCategoryForm.slug, (v) => setExamCategoryForm({ ...examCategoryForm, slug: slugify(v) }))}{textField('Icon', examCategoryForm.icon, (v) => setExamCategoryForm({ ...examCategoryForm, icon: v }))}{textField('Sort', examCategoryForm.sort, (v) => setExamCategoryForm({ ...examCategoryForm, sort: v }), 'number')}{checkboxField('Active', examCategoryForm.status, (v) => setExamCategoryForm({ ...examCategoryForm, status: v }))}{textAreaField('Description', examCategoryForm.description, (v) => setExamCategoryForm({ ...examCategoryForm, description: v }))}</FormGrid>{actionRow(() => saveExamCategory(), () => clearCategoryForms(), examCategoryForm.id ? () => deleteExamCategory() : undefined, examCategoryForm.id ? 'Update Exam Category' : 'Add Exam Category')}</>} formTitle={examCategoryForm.id ? 'Edit Exam Category' : 'Add Exam Category'} /><DualCard title="Blog Categories" columns={['Name','Slug','Status','Sort']} rows={filteredBlogCategories.map((item) => [item.name, item.slug, item.status || 'active', item.sort || 0])} onSelect={(index) => setBlogCategoryForm({ id: filteredBlogCategories[index]._id || filteredBlogCategories[index].id, name: filteredBlogCategories[index].name, slug: filteredBlogCategories[index].slug, icon: filteredBlogCategories[index].icon || '', sort: String(filteredBlogCategories[index].sort || 0), status: filteredBlogCategories[index].status || 'active', description: filteredBlogCategories[index].description || '' })} emptyLabel="No blog categories" form={<><FormGrid>{textField('Name', blogCategoryForm.name, (v) => setBlogCategoryForm({ ...blogCategoryForm, name: v, slug: blogCategoryForm.id ? blogCategoryForm.slug : slugify(v) }))}{textField('Slug', blogCategoryForm.slug, (v) => setBlogCategoryForm({ ...blogCategoryForm, slug: slugify(v) }))}{textField('Icon', blogCategoryForm.icon, (v) => setBlogCategoryForm({ ...blogCategoryForm, icon: v }))}{textField('Sort', blogCategoryForm.sort, (v) => setBlogCategoryForm({ ...blogCategoryForm, sort: v }), 'number')}{selectField('Status', blogCategoryForm.status, (v) => setBlogCategoryForm({ ...blogCategoryForm, status: v }), ['active','inactive'])}{textAreaField('Description', blogCategoryForm.description, (v) => setBlogCategoryForm({ ...blogCategoryForm, description: v }))}</FormGrid>{actionRow(() => saveBlogCategory(), () => clearCategoryForms(), blogCategoryForm.id ? () => deleteBlogCategory() : undefined, blogCategoryForm.id ? 'Update Blog Category' : 'Add Blog Category')}</>} formTitle={blogCategoryForm.id ? 'Edit Blog Category' : 'Add Blog Category'} /></div> : null}

        {tab === 'content' ? <div style={{ display: 'grid', gap: 20 }}><DualCard title="Blogs" columns={['Title','Slug','Status','Keywords']} rows={filteredBlogs.map((item) => [item.title, item.slug, item.status || 'draft', item.keywords || ''])} onSelect={(index) => setBlogForm({ id: filteredBlogs[index]._id || filteredBlogs[index].id, title: filteredBlogs[index].title, slug: filteredBlogs[index].slug, status: filteredBlogs[index].status || 'draft', description: filteredBlogs[index].description || '', keywords: filteredBlogs[index].keywords || '', blogCategoryId: filteredBlogs[index].blogCategoryId || '' })} emptyLabel="No blogs found" form={<><FormGrid>{textField('Title', blogForm.title, (v) => setBlogForm({ ...blogForm, title: v, slug: blogForm.id ? blogForm.slug : slugify(v) }))}{textField('Slug', blogForm.slug, (v) => setBlogForm({ ...blogForm, slug: slugify(v) }))}{selectField('Status', blogForm.status, (v) => setBlogForm({ ...blogForm, status: v }), ['draft','published','archived'])}{selectField('Blog Category', blogForm.blogCategoryId, (v) => setBlogForm({ ...blogForm, blogCategoryId: v }), [''].concat(blogCategories.data.map((item) => item._id || item.id || '')))}{textField('Keywords', blogForm.keywords, (v) => setBlogForm({ ...blogForm, keywords: v }))}{textAreaField('Description', blogForm.description, (v) => setBlogForm({ ...blogForm, description: v }))}</FormGrid>{actionRow(() => saveBlog(), () => clearContentForms(), blogForm.id ? () => deleteBlog() : undefined, blogForm.id ? 'Update Blog' : 'Add Blog')}</>} formTitle={blogForm.id ? 'Edit Blog' : 'Add Blog'} /><DualCard title="Pages" columns={['Name','Title','Slug','Type']} rows={filteredPages.map((item) => [item.name || '', item.title, item.slug, item.type || 'inner_page'])} onSelect={(index) => setPageForm({ id: filteredPages[index]._id || filteredPages[index].id, name: filteredPages[index].name || '', title: filteredPages[index].title, slug: filteredPages[index].slug, type: filteredPages[index].type || 'inner_page', active: filteredPages[index].active !== false, description: filteredPages[index].description || '' })} emptyLabel="No pages found" form={<><FormGrid>{textField('Name', pageForm.name, (v) => setPageForm({ ...pageForm, name: v }))}{textField('Title', pageForm.title, (v) => setPageForm({ ...pageForm, title: v, slug: pageForm.id ? pageForm.slug : slugify(v), name: pageForm.name || v }))}{textField('Slug', pageForm.slug, (v) => setPageForm({ ...pageForm, slug: slugify(v) }))}{selectField('Type', pageForm.type, (v) => setPageForm({ ...pageForm, type: v }), ['inner_page','marketing','legal','system'])}{checkboxField('Active', pageForm.active, (v) => setPageForm({ ...pageForm, active: v }))}{textAreaField('Description', pageForm.description, (v) => setPageForm({ ...pageForm, description: v }))}</FormGrid>{actionRow(() => savePage(), () => clearContentForms(), pageForm.id ? () => deletePage() : undefined, pageForm.id ? 'Update Page' : 'Add Page')}</>} formTitle={pageForm.id ? 'Edit Page' : 'Add Page'} /><DualCard title="Page Sections" columns={['Name','Slug','Page','Status']} rows={filteredSections.map((item) => [item.name, item.slug, item.pageId || '', item.active === false ? 'Inactive' : 'Active'])} onSelect={(index) => setSectionForm({ id: filteredSections[index]._id || filteredSections[index].id, name: filteredSections[index].name, slug: filteredSections[index].slug, title: filteredSections[index].title || '', sort: String(filteredSections[index].sort || 0), active: filteredSections[index].active !== false, pageId: filteredSections[index].pageId || '', description: filteredSections[index].description || '', backgroundColor: filteredSections[index].backgroundColor || '' })} emptyLabel="No page sections found" form={<><FormGrid>{textField('Name', sectionForm.name, (v) => setSectionForm({ ...sectionForm, name: v, slug: sectionForm.id ? sectionForm.slug : slugify(v) }))}{textField('Slug', sectionForm.slug, (v) => setSectionForm({ ...sectionForm, slug: slugify(v) }))}{textField('Title', sectionForm.title, (v) => setSectionForm({ ...sectionForm, title: v }))}{selectField('Page', sectionForm.pageId, (v) => setSectionForm({ ...sectionForm, pageId: v }), [''].concat(pages.data.map((item) => item._id || item.id || '')))}{textField('Sort', sectionForm.sort, (v) => setSectionForm({ ...sectionForm, sort: v }), 'number')}{checkboxField('Active', sectionForm.active, (v) => setSectionForm({ ...sectionForm, active: v }))}{textField('Background Color', sectionForm.backgroundColor, (v) => setSectionForm({ ...sectionForm, backgroundColor: v }))}{textAreaField('Description', sectionForm.description, (v) => setSectionForm({ ...sectionForm, description: v }))}</FormGrid>{actionRow(() => saveSection(), () => clearContentForms(), sectionForm.id ? () => deleteSection() : undefined, sectionForm.id ? 'Update Section' : 'Add Section')}</>} formTitle={sectionForm.id ? 'Edit Section' : 'Add Section'} /></div> : null}

        {tab === 'cms' ? <div style={{ display: 'grid', gap: 20 }}><DualCard title="Navbars" columns={['Title','Slug','Status','Items']} rows={filteredNavbars.map((item) => [item.title, item.slug, item.active === false ? 'Inactive' : 'Active', (item.items || []).length])} onSelect={(index) => setNavbarForm({ id: filteredNavbars[index]._id || filteredNavbars[index].id, title: filteredNavbars[index].title, slug: filteredNavbars[index].slug, active: filteredNavbars[index].active !== false, itemsText: navItemsToText(filteredNavbars[index].items) })} emptyLabel="No navbars found" form={<><FormGrid>{textField('Title', navbarForm.title, (v) => setNavbarForm({ ...navbarForm, title: v, slug: navbarForm.id ? navbarForm.slug : slugify(v) }))}{textField('Slug', navbarForm.slug, (v) => setNavbarForm({ ...navbarForm, slug: slugify(v) }))}{checkboxField('Active', navbarForm.active, (v) => setNavbarForm({ ...navbarForm, active: v }))}{textAreaField('Items', navbarForm.itemsText, (v) => setNavbarForm({ ...navbarForm, itemsText: v }), 'One per line: Title|/url|type|true')}</FormGrid>{actionRow(() => saveNavbar(), () => setNavbarForm({ title: '', slug: '', active: false, itemsText: '' }), navbarForm.id ? () => deleteNavbar() : undefined, navbarForm.id ? 'Update Navbar' : 'Add Navbar')}</>} formTitle={navbarForm.id ? 'Edit Navbar' : 'Add Navbar'} /><DualCard title="Footers" columns={['Title','Slug','Status','Items']} rows={filteredFooters.map((item) => [item.title, item.slug, item.active === false ? 'Inactive' : 'Active', (item.items || []).length])} onSelect={(index) => setFooterForm({ id: filteredFooters[index]._id || filteredFooters[index].id, title: filteredFooters[index].title, slug: filteredFooters[index].slug, active: filteredFooters[index].active !== false, itemsText: navItemsToText(filteredFooters[index].items) })} emptyLabel="No footers found" form={<><FormGrid>{textField('Title', footerForm.title, (v) => setFooterForm({ ...footerForm, title: v, slug: footerForm.id ? footerForm.slug : slugify(v) }))}{textField('Slug', footerForm.slug, (v) => setFooterForm({ ...footerForm, slug: slugify(v) }))}{checkboxField('Active', footerForm.active, (v) => setFooterForm({ ...footerForm, active: v }))}{textAreaField('Items', footerForm.itemsText, (v) => setFooterForm({ ...footerForm, itemsText: v }), 'One per line: Title|/url|type|true')}</FormGrid>{actionRow(() => saveFooter(), () => setFooterForm({ title: '', slug: '', active: false, itemsText: '' }), footerForm.id ? () => deleteFooter() : undefined, footerForm.id ? 'Update Footer' : 'Add Footer')}</>} formTitle={footerForm.id ? 'Edit Footer' : 'Add Footer'} /></div> : null}

        {tab === 'messages' ? <div style={{ display: 'grid', gap: 20 }}><DualCard title="Newsletters" columns={['Subject','Description','Created']} rows={filteredNewsletters.map((item) => [item.subject, String(item.description || '').slice(0, 90), fmtDate(item.createdAt)])} onSelect={(index) => setNewsletterForm({ id: filteredNewsletters[index]._id || filteredNewsletters[index].id, subject: filteredNewsletters[index].subject, description: filteredNewsletters[index].description })} emptyLabel="No newsletters found" form={<><FormGrid>{textField('Subject', newsletterForm.subject, (v) => setNewsletterForm({ ...newsletterForm, subject: v }))}{textAreaField('Description', newsletterForm.description, (v) => setNewsletterForm({ ...newsletterForm, description: v }))}</FormGrid>{actionRow(() => saveNewsletter(), () => setNewsletterForm({ subject: '', description: '' }), newsletterForm.id ? () => deleteNewsletter() : undefined, newsletterForm.id ? 'Update Newsletter' : 'Add Newsletter')}</>} formTitle={newsletterForm.id ? 'Edit Newsletter' : 'Add Newsletter'} /><div style={card}><h2 style={{ marginTop: 0 }}>Contact Messages</h2><SimpleTable columns={['Name','Email','Subject','Created']} rows={filteredMessages.map((item) => [item.name, item.email, item.subject || 'No subject', fmtDate(item.createdAt)])} emptyLabel="No contact messages" /><div style={{ marginTop: 16, display: 'grid', gap: 12 }}>{filteredMessages.map((item) => <div key={item._id || item.id} style={{ borderTop: '1px solid #e2e8f0', paddingTop: 12 }}><div style={{ fontWeight: 700 }}>{item.name} - {item.email}</div><div style={{ color: '#475569', marginTop: 4 }}>{item.message}</div><button type="button" onClick={() => deleteMessage(item._id || item.id)} style={{ marginTop: 10, padding: '8px 12px', borderRadius: 10, border: '1px solid #fecaca', background: '#fff1f2', color: '#b91c1c', fontWeight: 700, cursor: 'pointer' }}>Delete Message</button></div>)}</div></div></div> : null}

        {tab === 'settings' ? <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}><div style={card}><h2 style={{ marginTop: 0 }}>Platform Settings</h2><FormGrid>{textField('Site Name', settingsForm.siteName, (v) => setSettingsForm({ ...settingsForm, siteName: v }))}{textAreaField('Site Description', settingsForm.siteDescription, (v) => setSettingsForm({ ...settingsForm, siteDescription: v }))}{textAreaField('Social Links', settingsForm.socialLinks, (v) => setSettingsForm({ ...settingsForm, socialLinks: v }), 'One per line: Label|https://url')}</FormGrid>{actionRow(() => saveSettings(), () => setSettingsForm({ siteName: settings.data.siteName || '', siteDescription: settings.data.siteDescription || '', socialLinks: (settings.data.socialLinks || []).map((item: any) => `${item.label || ''}|${item.href || ''}`).join('\n') }), undefined, 'Update Settings')}</div><div style={card}><h2 style={{ marginTop: 0 }}>Current Summary</h2><div><strong>Site Name:</strong> {settings.data.siteName || 'EDVO'}</div><div style={{ marginTop: 10 }}><strong>Description:</strong> {settings.data.siteDescription || 'Not set'}</div><div style={{ marginTop: 10 }}><strong>Social Links:</strong></div><ul>{(settings.data.socialLinks || []).map((item: any, index: number) => <li key={`${item.label}-${index}`}>{item.label || 'Untitled'} - {item.href || 'No URL'}</li>)}</ul></div></div> : null}
      </div>
    </main>
  );
}

function DualCard({ title, columns, rows, onSelect, emptyLabel, form, formTitle }: { title: string; columns: string[]; rows: Array<Array<string | number>>; onSelect: (index: number) => void; emptyLabel: string; form: ReactNode; formTitle: string }) { return <div style={{ display: 'grid', gridTemplateColumns: '1.1fr 0.9fr', gap: 20 }}><div style={card}><h2 style={{ marginTop: 0 }}>{title}</h2><SimpleTable columns={columns} rows={rows} emptyLabel={emptyLabel} onSelect={onSelect} /></div><div style={card}><h2 style={{ marginTop: 0 }}>{formTitle}</h2>{form}</div></div>; }
function FormGrid({ children }: { children: ReactNode }) { return <div style={{ display: 'grid', gap: 14 }}>{children}</div>; }
function textField(label: string, value: string, onChange: (value: string) => void, type = 'text') { return <label style={{ display: 'grid', gap: 6 }}><span style={{ fontWeight: 700 }}>{label}</span><input type={type} value={value} onChange={(event) => onChange(event.target.value)} style={{ padding: 12, borderRadius: 10, border: '1px solid #cbd5e1' }} /></label>; }
function textAreaField(label: string, value: string, onChange: (value: string) => void, placeholder = '') { return <label style={{ display: 'grid', gap: 6 }}><span style={{ fontWeight: 700 }}>{label}</span><textarea value={value} onChange={(event) => onChange(event.target.value)} placeholder={placeholder} style={{ minHeight: 100, padding: 12, borderRadius: 10, border: '1px solid #cbd5e1' }} /></label>; }
function selectField(label: string, value: string, onChange: (value: string) => void, options: string[]) { return <label style={{ display: 'grid', gap: 6 }}><span style={{ fontWeight: 700 }}>{label}</span><select value={value} onChange={(event) => onChange(event.target.value)} style={{ padding: 12, borderRadius: 10, border: '1px solid #cbd5e1', background: '#fff' }}>{options.map((option) => <option key={option} value={option}>{option || 'Select'}</option>)}</select></label>; }
function checkboxField(label: string, value: boolean, onChange: (value: boolean) => void) { return <label style={{ display: 'flex', gap: 10, alignItems: 'center', fontWeight: 700 }}><input type="checkbox" checked={value} onChange={(event) => onChange(event.target.checked)} />{label}</label>; }
function actionRow(onSave: () => void, onClear: () => void, onDelete?: () => void, saveLabel = 'Save') { return <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', marginTop: 18 }}><button type="button" onClick={onSave} style={{ padding: '12px 18px', borderRadius: 10, border: 0, background: '#0f172a', color: '#fff', fontWeight: 700, cursor: 'pointer' }}>{saveLabel}</button><button type="button" onClick={onClear} style={{ padding: '12px 18px', borderRadius: 10, border: '1px solid #cbd5e1', background: '#fff', color: '#0f172a', fontWeight: 700, cursor: 'pointer' }}>Clear</button>{onDelete ? <button type="button" onClick={onDelete} style={{ padding: '12px 18px', borderRadius: 10, border: '1px solid #fecaca', background: '#fff1f2', color: '#b91c1c', fontWeight: 700, cursor: 'pointer' }}>Delete</button> : null}</div>; }
function SimpleTable({ columns, rows, emptyLabel, onSelect }: { columns: string[]; rows: Array<Array<string | number>>; emptyLabel: string; onSelect?: (index: number) => void }) { return <div style={{ overflowX: 'auto' }}><table style={{ width: '100%', borderCollapse: 'collapse' }}><thead><tr>{columns.map((column) => <th key={column} style={{ textAlign: 'left', padding: '0 0 12px', fontSize: 12, color: '#64748b', textTransform: 'uppercase' }}>{column}</th>)}</tr></thead><tbody>{rows.length ? rows.map((row, rowIndex) => <tr key={`${rowIndex}-${row.join('-')}`} onClick={() => onSelect?.(rowIndex)} style={{ cursor: onSelect ? 'pointer' : 'default' }}>{row.map((cell, cellIndex) => <td key={`${rowIndex}-${cellIndex}`} style={{ padding: '12px 0', borderTop: '1px solid #e2e8f0', verticalAlign: 'top' }}>{cell}</td>)}</tr>) : <tr><td colSpan={columns.length} style={{ padding: '14px 0', borderTop: '1px solid #e2e8f0', color: '#64748b' }}>{emptyLabel}</td></tr>}</tbody></table></div>; }
